  const starts = ['\n      <tr><td', '\n                        <tr><td', '<tr><td', '<tr>'];
  let start = -1;
  for (const needle of starts) {
    const pos = html.lastIndexOf(needle, index);
    if (pos !== -1 && pos > start) start = pos;
  }
  if (start === -1) start = Math.max(0, index - 200);
  const ends = ['\n      <tr><td', '\n                        <tr><td', '\n      <tr><td style="background-color', '\n                        <tr><td style="background-color'];
  let end = -1;
  for (const needle of ends) {
